mapper.select:
SELECT COUNT(1)
FROM agent_task


        AND user_id = #{userId}


        AND status = #{status}


        AND (
            LOWER(COALESCE(title, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%')
            OR LOWER(COALESCE(goal, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%')
        )

SELECT
    id, user_id, session_id, task_type, title, goal, status, execution_mode,
    search_scope, allow_draft_write, current_step, final_output_summary,
    error_message, started_at, completed_at, created_at, updated_at
FROM agent_task


        AND user_id = #{userId}


        AND status = #{status}


        AND (
            LOWER(COALESCE(title, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%')
            OR LOWER(COALESCE(goal, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%')
        )


ORDER BY created_at DESC
LIMIT #{offset}, #{limit}
